import{_ as e,o as a,c as i,a3 as s}from"./chunks/framework.LBeL10WQ.js";const u=JSON.parse('{"title":"Spécifications Bannières","description":"","frontmatter":{"title":"Spécifications Bannières"},"headers":[],"relativePath":"advertisers/display-email/specs.md","filePath":"advertisers/display-email/specs.md"}'),r={name:"advertisers/display-email/specs.md"};function n(l,t,o,d,c,p){return a(),i("div",null,[...t[0]||(t[0]=[s('<h1 id="specifications-bannieres" tabindex="-1">Spécifications Bannières <a class="header-anchor" href="#specifications-bannieres" aria-label="Permalink to &quot;Spécifications Bannières&quot;">​</a></h1><p>Standards à respecter pour garantir un affichage optimal sur tous les clients mail (Outlook, Gmail, Apple Mail…).</p><hr><h2 id="formats-standards" tabindex="-1">Formats Standards <a class="header-anchor" href="#formats-standards" aria-label="Permalink to &quot;Formats Standards&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Format</th><th style="text-align:left;">Dimensions (L × H)</th><th style="text-align:left;">Emplacement typique</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Bannière Large</strong> (Leaderboard)</td><td style="text-align:left;"><strong>600 × 150 px</strong> <em>(parfois 640 px)</em></td><td style="text-align:left;">Header ou cœur de mail — format le plus impactant</td></tr><tr><td style="text-align:left;"><strong>Pavé</strong> (Rectangle)</td><td style="text-align:left;"><strong>300 × 250 px</strong></td><td style="text-align:left;">Colonne latérale ou pied de mail — format compact</td></tr></tbody></table><hr><h2 id="contraintes-techniques" tabindex="-1">Contraintes Techniques <a class="header-anchor" href="#contraintes-techniques" aria-label="Permalink to &quot;Contraintes Techniques&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Critère</th><th style="text-align:left;">Spécification</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Type de fichier</strong></td><td style="text-align:left;">JPG, PNG ou GIF</td></tr><tr><td style="text-align:left;"><strong>Mode colorimétrique</strong></td><td style="text-align:left;">RVB</td></tr><tr><td style="text-align:left;"><strong>Poids maximum</strong></td><td style="text-align:left;">150 Ko — recommandé &lt; <strong>80 Ko</strong> pour un chargement rapide sur mobile</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">GIF animés — règle de la première frame</p><p>Les GIFs animés sont acceptés, mais <strong>Outlook (versions bureau) n&#39;affiche que la première image</strong>.</p><p>→ L&#39;information principale et le Call-to-Action doivent impérativement figurer sur la <strong>première frame</strong>.</p></div><hr><h2 id="bonnes-pratiques-design" tabindex="-1">Bonnes Pratiques Design <a class="header-anchor" href="#bonnes-pratiques-design" aria-label="Permalink to &quot;Bonnes Pratiques Design&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Fond blanc : ajoutez une bordure</p><p>Si votre bannière a un fond blanc, elle risque de se fondre dans l&#39;arrière-plan de l&#39;email et de devenir invisible.</p><p>Ajoutez une <strong>bordure grise de 1 px</strong> (<code>#cccccc</code>) tout autour de votre visuel pour bien la délimiter.</p></div><div class="tip custom-block"><p class="custom-block-title">Lisibilité mobile</p><p>Sur mobile, une bannière 600 px est réduite à ~350 px de large. Évitez les polices trop fines ou trop petites — <strong>taille minimum recommandée : 16 px</strong>.</p></div>',13)])])}const g=e(r,[["render",n]]);export{u as __pageData,g as default};
